<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title>Mini Spreadsheet</title>
<style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: Arial, sans-serif; margin: 20px; background: #fafafa; }
    #app { min-width: 600px; min-height: 400px; }
    #grid {
        display: grid;
        grid-template-columns: 40px repeat(10, 80px);
        grid-template-rows: 30px repeat(10, 36px);
        gap: 1px;
        background: #bbb;
        border: 1px solid #bbb;
        width: fit-content;
    }
    .header {
        background: #e8e8e8;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: bold;
        font-size: 13px;
        color: #333;
    }
    .corner { background: #d0d0d0; }
    input {
        width: 100%;
        height: 100%;
        border: none;
        padding: 2px 4px;
        font-size: 13px;
        font-family: 'Courier New', monospace;
        background: #fff;
    }
    input:focus { outline: 2px solid #4a90d9; background: #fff; z-index: 1; position: relative; }
    input:hover { background: #f5f5f5; }
    #export { margin-top: 12px; padding: 8px 18px; cursor: pointer; font-size: 14px; background: #4a90d9; color: #fff; border: none; border-radius: 4px; }
    #export:hover { background: #357abd; }
    #csv { width: 100%; height: 180px; margin-top: 10px; font-family: 'Courier New', monospace; font-size: 13px; padding: 8px; border: 1px solid #ccc; border-radius: 4px; resize: vertical; }
</style>
</head>
<body>
<div id="app">
    <div id="grid"></div>
    <button id="export">Export CSV</button>
    <textarea id="csv"></textarea>
</div>
<script>
(function() {
    const rawValues = {};
    const cache = {};
    const evalStack = [];
    const cycleCells = new Set();

    const grid = document.getElementById('grid');

    const corner = document.createElement('div');
    corner.className = 'header corner';
    grid.appendChild(corner);

    for (let col = 0; col < 10; col++) {
        const header = document.createElement('div');
        header.className = 'header';
        header.textContent = String.fromCharCode(65 + col);
        grid.appendChild(header);
    }

    for (let row = 0; row < 10; row++) {
        const rowHeader = document.createElement('div');
        rowHeader.className = 'header';
        rowHeader.textContent = row + 1;
        grid.appendChild(rowHeader);

        for (let col = 0; col < 10; col++) {
            const cellId = String.fromCharCode(65 + col) + (row + 1);
            const input = document.createElement('input');
            input.id = 'cell-' + cellId;
            input.type = 'text';
            input.setAttribute('autocomplete', 'off');
            grid.appendChild(input);

            input.addEventListener('focus', function() {
                const cid = this.id.substring(5);
                this.value = rawValues[cid] || '';
            });

            input.addEventListener('blur', function() {
                const cid = this.id.substring(5);
                rawValues[cid] = this.value;
                recalculate();
            });

            input.addEventListener('keydown', function(e) {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    this.blur();
                }
            });
        }
    }

    function recalculate() {
        for (const key in cache) delete cache[key];
        cycleCells.clear();
        evalStack.length = 0;

        for (let col = 0; col < 10; col++) {
            for (let row = 0; row < 10; row++) {
                const cellId = String.fromCharCode(65 + col) + (row + 1);
                getCellValue(cellId);
            }
        }

        for (const cellId of cycleCells) {
            cache[cellId] = { value: '#CYCLE', display: '#CYCLE' };
        }

        const focused = document.activeElement;
        for (let col = 0; col < 10; col++) {
            for (let row = 0; row < 10; row++) {
                const cellId = String.fromCharCode(65 + col) + (row + 1);
                const input = document.getElementById('cell-' + cellId);
                if (input && input !== focused) {
                    input.value = cache[cellId].display;
                }
            }
        }
    }

    function getCellValue(cellId) {
        if (cellId in cache) return cache[cellId];

        const raw = rawValues[cellId] || '';

        if (!raw.startsWith('=')) {
            const trimmed = raw.trim();
            if (trimmed === '') {
                cache[cellId] = { value: 0, display: '' };
            } else {
                const num = Number(trimmed);
                if (!isNaN(num) && isFinite(num)) {
                    cache[cellId] = { value: num, display: String(num) };
                } else {
                    cache[cellId] = { value: raw, display: raw };
                }
            }
            return cache[cellId];
        }

        if (evalStack.includes(cellId)) {
            const idx = evalStack.indexOf(cellId);
            for (let i = idx; i < evalStack.length; i++) {
                cycleCells.add(evalStack[i]);
            }
            cache[cellId] = { value: '#CYCLE', display: '#CYCLE' };
            return cache[cellId];
        }

        evalStack.push(cellId);

        try {
            const result = evalFormula(raw.substring(1));
            if (isNaN(result) || !isFinite(result)) {
                cache[cellId] = { value: '#ERR', display: '#ERR' };
            } else {
                cache[cellId] = { value: result, display: String(result) };
            }
        } catch (e) {
            cache[cellId] = { value: '#ERR', display: '#ERR' };
        }

        evalStack.pop();
        return cache[cellId];
    }

    function evalFormula(formula) {
        let pos = 0;

        function peek() { return formula[pos]; }
        function consume() { return formula[pos++]; }
        function skipSpaces() { while (pos < formula.length && formula[pos] === ' ') pos++; }

        function parseExpression() {
            let result = parseTerm();
            skipSpaces();
            while (pos < formula.length && (peek() === '+' || peek() === '-')) {
                const op = consume();
                skipSpaces();
                const right = parseTerm();
                if (op === '+') result = result + right;
                else result = result - right;
                skipSpaces();
            }
            return result;
        }

        function parseTerm() {
            let result = parseFactor();
            skipSpaces();
            while (pos < formula.length && (peek() === '*' || peek() === '/')) {
                const op = consume();
                skipSpaces();
                const right = parseFactor();
                if (op === '*') result = result * right;
                else result = result / right;
                skipSpaces();
            }
            return result;
        }

        function parseFactor() {
            skipSpaces();
            if (pos >= formula.length) throw new Error('Unexpected end of formula');

            if (peek() === '-') {
                consume();
                return -parseFactor();
            }

            if (peek() === '(') {
                consume();
                const result = parseExpression();
                skipSpaces();
                if (peek() !== ')') throw new Error('Missing closing parenthesis');
                consume();
                return result;
            }

            if (peek() >= '0' && peek() <= '9') {
                let numStr = '';
                while (pos < formula.length && (formula[pos] >= '0' && formula[pos] <= '9' || formula[pos] === '.')) {
                    numStr += consume();
                }
                return parseFloat(numStr);
            }

            if (peek() >= 'A' && peek() <= 'J') {
                const col = consume();
                let rowStr = '';
                while (pos < formula.length && formula[pos] >= '0' && formula[pos] <= '9') {
                    rowStr += consume();
                }
                if (rowStr === '') throw new Error('Invalid cell reference');
                const row = parseInt(rowStr);
                if (row < 1 || row > 10) throw new Error('Invalid cell reference');
                const refCellId = col + rowStr;
                const cellInfo = getCellValue(refCellId);
                if (cellInfo.value === '#CYCLE' || cellInfo.value === '#ERR') {
                    throw new Error(cellInfo.value);
                }
                if (typeof cellInfo.value === 'string') {
                    const num = Number(cellInfo.value);
                    if (isNaN(num) || !isFinite(num)) throw new Error('Non-numeric value');
                    return num;
                }
                return cellInfo.value;
            }

            throw new Error('Unexpected character: ' + peek());
        }

        const result = parseExpression();
        skipSpaces();
        if (pos < formula.length) throw new Error('Unexpected characters after formula');
        return result;
    }

    window.sheet = {
        set: function(cellId, value) {
            rawValues[cellId] = value;
            recalculate();
        },
        get: function(cellId) {
            if (!(cellId in cache)) recalculate();
            return cache[cellId].display;
        },
        raw: function(cellId) {
            return rawValues[cellId] || '';
        }
    };

    document.getElementById('export').addEventListener('click', function() {
        let csv = '';
        for (let row = 1; row <= 10; row++) {
            const rowValues = [];
            for (let col = 0; col < 10; col++) {
                const cellId = String.fromCharCode(65 + col) + row;
                rowValues.push(window.sheet.get(cellId));
            }
            csv += rowValues.join(',') + '\n';
        }
        document.getElementById('csv').value = csv;
    });

    recalculate();
})();
</script>
</body>
</html>
